import{_ as e,c as p,o,ae as t}from"./chunks/framework.BvcDoAct.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ja-jp/Management2/PART2/9.md","filePath":"ja-jp/Management2/PART2/9.md"}'),n={name:"ja-jp/Management2/PART2/9.md"};function r(S,a,s,B,i,T){return o(),p("div",null,[...a[0]||(a[0]=[t('<p>► 2023/03</p><h2 id="bmsgを支えるb-town、その重要性とリニューアルの狙い" tabindex="-1">BMSGを支えるB-Town、その重要性とリニューアルの狙い <a class="header-anchor" href="#bmsgを支えるb-town、その重要性とリニューアルの狙い" aria-label="Permalink to &quot;BMSGを支えるB-Town、その重要性とリニューアルの狙い&quot;">​</a></h2><p>#ファンコミュニティ #オンラインサロン #コミュニケーション #発信の方法 #B-TOWN</p><h3 id="「本来、コミュニケーションって前提条件や相手の状況によって全く違うアプローチをしないといけないと思う」" tabindex="-1">「本来、コミュニケーションって前提条件や相手の状況によって全く違うアプローチをしないといけないと思う」 <a class="header-anchor" href="#「本来、コミュニケーションって前提条件や相手の状況によって全く違うアプローチをしないといけないと思う」" aria-label="Permalink to &quot;「本来、コミュニケーションって前提条件や相手の状況によって全く違うアプローチをしないといけないと思う」&quot;">​</a></h3><p><strong>BMSG設立から間もない2020年10月10日に始まったファンコミュニティ「B-Town」。月額5000円の「Architect」と月額500円の「Resident」の2つのコースがあり、「Architect」ではBMSGの経営や今後の展開など、まだ世に発表されていない貴重な話が聞けるとともに、SKY-HIの手記やアーティストのインスタライブ、スタッフの話など、ここだけのコンテンツが発信されている。まだ歴史の浅いBMSGが、応援してくれるファンと共に歩んでいくような意味合いも強い。</strong></p><p><strong>その「B-Town」が、23年3月、新たにオンラインサロンとして仕切り直しを行った。テコ入れに着手したのはなぜなのか。まずは、改めて当初「B-Town」の運営を決めた理由から聞いた。</strong></p><p>「B-Town」を立ち上げた理由はたくさんあるのですが、1つの大きな理由は、自分が伝えたいことを発信する場が必要だったからです。</p><p>20年の段階で、僕はSNSでの情報の拡散のされ方に対して、諦めている状態でした。捻じ曲がった解釈がそのまま広がり、つまりは発信者と受信者の間で正しくコミュニケーションが行われるとは限らない。見る人が多ければそれは当然起こりうるのですが、そうしたSNSでのコミュニケーションを諦めざるを得ない気持ちになっていたんです。</p><p>そもそも誰もが目にすることができるSNSでは、ユーザーの性別・年齢・その人がいる環境などがまるで違う。例えば、アメリカから来日して間もない人にたこ焼きの話をするときには、たこ焼きはどんな食べ物かも伝える必要があるけれども、日本人にたこ焼きの話をする際にはその説明はいらないじゃないですか。本来、コミュニケーションってそうした前提条件や相手の状況によって全く違うアプローチをしないといけないと思うんです。それをオープンなSNSですることに限界を感じました。</p><p>でも、芸能全体の変革のためにBMSGを立ち上げた自分には、「何をやるのか」「何を問題だと思っているのか」「そのためにどうするのか」を発信し続けていく場所も必要でした。独立・起業した人間がどんなことをしているのかを発信するのも社会にとって大事だと思いましたし、数年後には、今やっていることの答え合わせもできるでしょう。そして視点を変えると、ゲームでもアニメでもマンガでもなく、1人の人間の人生をかけた、失敗するか成功するかも分からない現実をリアルタイムで見られる場なんてそうそうありません。</p><p>なので、発信すべきだという考えのもとに受信先の前提条件だったのが、「BMSGを応援してくれる人」となったわけです。しかもそのために大きなお金を払ってくれる方となると、冷やかしでは入りにくい。その場所で共通言語の持てるファンや応援者との密なコミュニケーションができたらと考えました。</p><p>月額5000円は高いと感じる価格設定かもしれません。しかし外部には非公開の情報も多く、「B-Town」で発信していることを隅々まで読み解けば、僕らがやろうとしていることを先に誰かにされてしまう可能性もあるような内容です。本当は「ちょっとBMSGに興味がある」という方にも気軽に入っていただきたい気持ちもあるのですが、そうした情報流出の危険性も考えて、ハードルを上げているところがあります。</p><h3 id="「コミュニティとしての機能」を見直す時期に" tabindex="-1">「コミュニティとしての機能」を見直す時期に <a class="header-anchor" href="#「コミュニティとしての機能」を見直す時期に" aria-label="Permalink to &quot;「コミュニティとしての機能」を見直す時期に&quot;">​</a></h3><p><strong>誕生から約2年半、「B-Town」が「ファンコミュニティ」から「オンラインサロン」へと定義のし直しをしたことには2つの理由があった。1つ目は改めて機能と役割を明確化すべきだったことだ。</strong></p><p>「ファンコミュニティ」という抽象的な言葉を使うことには、良さと悪さがあると思っていたんです。</p><p>良さで言えば、バッファが利く。立ち上げたばかりの会社だから、初期はコンテンツの種類もあまりなかった。当時はまだ僕にもNovelCoreにもそれぞれのファンクラブがありませんでした。当然いつファンクラブを作るかも議論し続けていたのですが、それまでは「ファンコミュニティ」があれば様々なことができると考えました。ファンクラブでもない、オンラインサロンでもない。その間を取って「ファンコミュニティ」としたんです。</p><p>ただ、アーティストの数が増え、応援してくださる方が増えていくと、「ファンコミュニティ」としての機能は難しくなりました。言葉が曖昧なゆえに、会員の方がB-Townに期待するものや要望・要求にもバッファが利いてしまう。つまり運営側と会員側にイメージのズレが生じるようになってしまう。マイナーチェンジは続けてきたのですが、今回、CAMPFIREさん内での運営から、完全自社運営に切り替えるタイミングで、リニューアルを図りました。</p><p>21年からファンクラブ、ECなど、地道に1つひとつ自社運営の体制を整えてきたのですが、昨年12月にほぼ形がまとまったので、ようやくB-Townにも着手できたというところです。</p><p><strong>2つ目の理由は、BMSGの成功によって「オンラインサロン」という言葉を使っても遜色ないフェーズに来たと判断したことだ。</strong></p><p>「オンラインサロン」って何らかの成功をし、自分の知見や経験を第三者に対して伝えるフェーズの人がやるもの、というイメージがありました。だから創業当初は「オンラインサロン」を名乗ることには抵抗があったんです。自分に何か学びのある提供ができるだろうか、と。</p><p>でも、今の段階では考え方次第ですが、確実に実績として芸能事務所、スタートアップ企業の両面から体面として「成功してます」と言える、および言わなくてはいけないフェーズに来ていると思いますし、その成功が瞬間的なものでもないと自負しています。今も外の人に「すごいですね」と言われると、「いや、まだまだこれからですよ」と言うことはあるし、それは事実なんだけれども、その自信はあるので、あまり不必要な謙遜を言わないように気をつけているところです。</p><p><strong>現在、「Architect」コースの会員数は1万人近く。かつてSKY-HIが「THE FIRST」を始める際に“自腹1億円を投じた”ことが話題になったが、今では1万人近くが月額5000円を出している状況だ。財務面でも社会的信用につながっているのでは?と下世話な質問をしてみたが、それ以上にB-Townの手応えを23年2月に本格始動したダンス&amp;ボーカルの大型プロジェクト「D.U.N.K.-DANCE UNIVERSE NEVER KILLED-」に感じたという。</strong></p><h3 id="発信してきて良かったという実感" tabindex="-1">発信してきて良かったという実感 <a class="header-anchor" href="#発信してきて良かったという実感" aria-label="Permalink to &quot;発信してきて良かったという実感&quot;">​</a></h3><p>ありがたいですよね。立ち上げからしばらくは税理士さんにも破産する可能性を言われ、僕も「実家で暮らすことになるかもな」と考えましたし。</p><p>特に「B-Town」が始まって、まだ「THEFIRST」の盛り上がりもなかった頃に400~500人の方がいてくださったことには感謝していますし、無条件でこんなに応援してくれるなら、と僕のカになりましたし、1期目での身売りや倒産も防げました。</p><p>そして今、BMSGの自社ビル計画を考え始めているのですが、こればかりは銀行からお金を借りないと進まない。ようやくBMSGに対して銀行がお金を貸してくれるようになった1つの基盤もまた「B-Town」のおかげだと思っています。</p><p>もう1つ、(3月5・11・12日開催の)「D.U.N.K.Showcase」で、ようやく「B-Town」で話していたことの答え合わせができたと感じたんです。「こうあるべき」をずっと話し続けて、年月がたってようやく浸透していくものがあるなと。事務所やジャンル、カテゴライズの垣根を取っ払い、純粋に音楽を楽しむ場を作りたかったのが「D.U.N.K.」の意義の1つなんですが、「D.U.N.K.Showcase」は、どのアーティストが出演しているときも会場の空気感が素晴らしかったんです。</p><p>複数のアーティストが出る通常のイベントって、推しを見に来たり、推しに見てもらったりが目的になるケースもあると思うんです。それがすなわち悪いというわけではないのですが、もっと音楽を純粋に楽しんでもらうためにはどうしたらいいかをずっと考え続けていたわけです。そして発信し続けていた「こうあるべき」が浸透した結果が、あの場の空気の良さにつながった。「B-Town」のおかげと言っても過言ではないと思います。</p><p>対外的には「BMSG FES」の成功も大きかったかもしれません。「BMSG FES」以降で同業他社からのBMSGの見られ方も大きく変わったし、自分たちの立ち位置も明確になっていろいろなことがやりやすくなったんです。おそらく「最近、BE:FIRSTって人気だね」を超えて、「BMSGと一緒に仕事をしてみたい」が増えたのも「BMSG FES」からで、異業種の方々とも本当に仕事をしゃ すくなりましたね。</p><p>その会社としての核でもある「BMSG FES」を下支えしているのも、「BMSGとは何ぞや」を理解し、応援してくれている「B-Town」なのかなと思います。</p>',30)])])}const l=e(n,[["render",r]]);export{h as __pageData,l as default};
